import React, { useState } from 'react';
import './App.css';
import { BrowserRouter as Router, Routes, Route, Outlet, Link } from 'react-router-dom';

import Auth from './components/Auth';
import Login from './Js/Login';
import Signup from './Js/Signup';
import Dashboard from './Js/Dashboard';
import CreateProblem from './Js/CreateProblem';
import Problem from './Js/Problem';
import ProblemList from './Js/ProblemList';

function Layout({ user }) {
  return (
    <body>

    <div className="app-container">
      <header className="app-header">
        <div className="header-content">
          <h1 className="app-title">Math App</h1>
          <nav className="nav-links">
            <Link to="/dashboard" className="nav-link">Dashboard</Link>
            <Link to="/problems" className="nav-link">Problems</Link>
            {user?.role === 'admin' && (
              <Link to="/create-problem" className="nav-link">Create Problem</Link>
            )}
          </nav>
          {user && (
            <div className="user-info">
              <span>Hello, {user.username}</span>
            </div>
          )}
        </div>
      </header>

      <main className="app-main">

      </main>

      <footer className="app-footer">
        <p>&copy; 2025 Math App | Built with React</p>
      </footer>
    </div>
          </body>
  );
}

function App() {
  const [user, setUser] = useState(() => {
    // Load user from localStorage if exists (optional)
    const savedUser = localStorage.getItem('user');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  return (
    <Router>
      <div className="App">
        <Routes>
          {/* Public routes without layout */}
          <Route path="/" element={<Auth />} />
          <Route path="/login" element={<Login setUser={setUser} />} />
          <Route path="/signup" element={<Signup />} />

          {/* Routes with common layout */}
          <Route element={<Layout user={user} />}>
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/problems" element={<ProblemList />} />
            <Route path="/problems/:id" element={<Problem />} />
            <Route path="/create-problem" element={<CreateProblem />} />
          </Route>
        </Routes>
      </div>
    </Router>
  );
}

export default App;
